/**
 * fix-stale-dep-counts.js
 *
 * Updates stale exact-count assertions in auto-generated tests.
 * Changes `expect(X.length).toBe(N)` → `expect(X.length).toBeGreaterThanOrEqual(N_actual)`
 * for npm-dep and local-dep count checks.
 *
 * Only touches test files generated by the P#106 universal generator
 * (identified by the @generated header comment).
 *
 * Safe: only changes count assertions where the actual count differs from expected.
 * Does not touch logic, structure, or export assertions.
 */
'use strict';

const fs = require('fs');
const path = require('path');

const TESTS_DIR = path.resolve(__dirname, '../../tests/unit');

// Pattern to detect auto-generated test files
const GENERATED_RE = /@generated by P#106/;
// Pattern to extract SRC path
const SRC_RE = /const SRC = path\.resolve\(__dirname, '([^']+)'\)/;
// Pattern: toBe(N) for dep count checks
const NPM_ASSERT_RE = /expect\(npms\.length\)\.toBe\((\d+)\)/;
const LOCAL_ASSERT_RE = /expect\(locals\.length\)\.toBe\((\d+)\)/;
// Regex for local require calls in source (paths starting with . or ..)
const LOCAL_REQ_RE = /require\s*\(\s*['"][.][^'"]+['"]\s*\)/g;
// Regex for npm require calls (paths NOT starting with . or ..)
const NPM_REQ_RE = /require\s*\(\s*['"](?![./])[^'"]+['"]\s*\)/g;

let fixed = 0;
let skipped = 0;
let errors = 0;

const testFiles = fs.readdirSync(TESTS_DIR).filter(f => f.endsWith('.test.js'));

for (const testFile of testFiles) {
  const testPath = path.join(TESTS_DIR, testFile);
  const testSrc = fs.readFileSync(testPath, 'utf8');

  if (!GENERATED_RE.test(testSrc)) continue; // skip non-generated tests

  const srcMatch = testSrc.match(SRC_RE);
  if (!srcMatch) continue;

  const srcRel = srcMatch[1];
  const srcAbs = path.resolve(TESTS_DIR, srcRel);

  if (!fs.existsSync(srcAbs)) continue; // skip ENOENT (already deleted or will be)

  let source;
  try {
    source = fs.readFileSync(srcAbs, 'utf8');
  } catch (_e) {
    errors++;
    continue;
  }

  const actualNpm = (source.match(NPM_REQ_RE) || []).length;
  const actualLocal = (source.match(LOCAL_REQ_RE) || []).length;

  let changed = false;
  let newSrc = testSrc;

  const npmMatch = testSrc.match(NPM_ASSERT_RE);
  if (npmMatch) {
    const expected = parseInt(npmMatch[1], 10);
    if (expected !== actualNpm) {
      // Replace exact toBe with toBeGreaterThanOrEqual using actual count
      newSrc = newSrc.replace(
        `expect(npms.length).toBe(${expected})`,
        `expect(npms.length).toBeGreaterThanOrEqual(${actualNpm})`
      );
      changed = true;
    }
  }

  const localMatch = newSrc.match(LOCAL_ASSERT_RE);
  if (localMatch) {
    const expected = parseInt(localMatch[1], 10);
    if (expected !== actualLocal) {
      newSrc = newSrc.replace(
        `expect(locals.length).toBe(${expected})`,
        `expect(locals.length).toBeGreaterThanOrEqual(${actualLocal})`
      );
      changed = true;
    }
  }

  if (changed) {
    fs.writeFileSync(testPath, newSrc, 'utf8');
    fixed++;
  } else {
    skipped++;
  }
}

console.log(`Fixed: ${fixed} | Already correct: ${skipped} | Errors: ${errors}`);
